import type { SubmitEvent } from "react";
import { useState } from "react";

import type { ChatComposerProps, ChatComposerSubmitPayload } from "../contracts";

function useControllableText({
  value,
  defaultValue = "",
  onValueChange,
}: Pick<ChatComposerProps, "value" | "defaultValue" | "onValueChange">) {
  const [internalValue, setInternalValue] = useState(defaultValue);
  const isControlled = value !== undefined;
  const currentValue = isControlled ? value : internalValue;

  function setValue(nextValue: string) {
    if (!isControlled) setInternalValue(nextValue);
    onValueChange?.(nextValue);
  }

  return [currentValue, setValue] as const;
}

export function useChatComposer({
  value,
  defaultValue,
  onValueChange,
  onSubmit,
  state = "idle",
  density = "comfortable",
  disabled = false,
  trackSends = false,
}: Pick<ChatComposerProps, "value" | "defaultValue" | "onValueChange" | "onSubmit" | "state" | "density" | "disabled"> & {
  /** Count successful submits — only enabled when something reads the counter (the send-layer anchor), so idle apps pay no extra state update. */
  trackSends?: boolean;
}) {
  const [inputValue, setInputValue] = useControllableText({ value, defaultValue, onValueChange });
  const [sendCount, setSendCount] = useState(0);
  const normalizedValue = inputValue.trim();
  const isDisabled = disabled || state === "disabled" || state === "submitting";
  const canSubmit = normalizedValue.length > 0 && !isDisabled;
  const isCompact = density === "compact";

  function clear() {
    setInputValue("");
  }

  // shared path: plain textarea via handleSubmit, rich editor calls submit() directly with extras (mentions)
  function submit(extra?: Partial<ChatComposerSubmitPayload>) {
    if (!canSubmit) return;
    if (trackSends) setSendCount((count) => count + 1);
    void onSubmit?.({ value: normalizedValue, clear, ...extra });
  }

  function handleSubmit(event: SubmitEvent<HTMLFormElement>) {
    event.preventDefault();
    submit();
  }

  return {
    value: inputValue,
    setValue: setInputValue,
    normalizedValue,
    state,
    density,
    isCompact,
    isDisabled,
    canSubmit,
    rows: isCompact ? 2 : 4,
    sendCount,
    clear,
    submit,
    handleSubmit,
  };
}

/*
 * Blur choreography, token-driven (kill-switch collapses to 0).
 * Entry: pill blurs+scales IN via @starting-style (freshly appended by ProseMirror). Exit: pill-delete/message-submit blur OUT via [data-chat-composer-exit] on a throwaway clone (ghost.ts) since ProseMirror removes nodes synchronously.
 * Reads the shared --duration-* and --ease-* tokens.
 */

@layer components {
  /* resting look + blur-IN transition; :not([data-chat-composer-exit] *) excludes exit ghosts/cloned pills from entry choreography */
  :where([data-control-ui="chat-composer"][data-slot="mention"]):not([data-chat-composer-exit]):not([data-chat-composer-exit] *) {
    opacity: 1;
    filter: blur(0);
    scale: 1;
    transition:
      opacity var(--duration-base) var(--ease-emphasized),
      filter var(--duration-base) var(--ease-emphasized),
      scale var(--duration-base) var(--ease-emphasized);
  }

  @starting-style {
    :where([data-control-ui="chat-composer"][data-slot="mention"]):not([data-chat-composer-exit]):not([data-chat-composer-exit] *) {
      opacity: 0;
      filter: blur(6px);
      scale: 0.82;
    }
  }

  /* exit ghost: fixed-position clone, keyframe blurs it out then self-removes on animationend; finite duration lets kill-switch snap it away invisibly */
  :where([data-chat-composer-exit][data-exiting]) {
    opacity: 1;
    filter: blur(0);
    scale: 1;
    translate: 0 0;
    animation: chat-composer-blur-out var(--duration-base) var(--ease-emphasized) forwards;
  }
}

@keyframes chat-composer-blur-out {
  to {
    opacity: 0;
    filter: blur(8px);
    scale: 0.94;
    translate: 0 -0.25rem;
  }
}

"use client";

import { baseKeymap, splitBlock } from "prosemirror-commands";
import { history, redo, undo } from "prosemirror-history";
import { keymap } from "prosemirror-keymap";
import { EditorState, Plugin } from "prosemirror-state";
import { EditorView } from "prosemirror-view";
import { useEffect, useRef, useState } from "react";

import { useChatComposerContext } from "@/components/control-ui/chat-composer";
import type { ChatComposerSubmitPayload } from "@/components/control-ui/contracts";
import { cn } from "@/components/control-ui/lib/cn";
import { MESSAGE_GHOST_INHERIT, spawnExitGhost } from "./chat-composer-editor/ghost";
import { createEditorSchema } from "./chat-composer-editor/schema";
import { docFromText, serializeDoc } from "./chat-composer-editor/serialize";
import type { ChatComposerEditorApi, ChatComposerEditorProps } from "./chat-composer-editor/types";

const SUBMIT_KEY = "Enter";

// Bare ProseMirror editor (plain-text paragraphs only); extensions add nodes/plugins/keymap/overlay (e.g. mentionExtension), editor works with none.
// Doc is source of truth: pushes serialized text to chat-composer hook; re-hydrates only on EXTERNAL value changes (clear/prefill), never own keystrokes (would fight caret).
export function ChatComposerEditor({ className, placeholder, extensions = [] }: ChatComposerEditorProps) {
  const input = useChatComposerContext();

  const mountRef = useRef<HTMLDivElement>(null);
  const viewRef = useRef<EditorView | null>(null);
  const inputRef = useRef(input);
  useEffect(() => {
    inputRef.current = input;
  }, [input]);
  // Editor's own last output; lets reset effect distinguish external value change from own keystroke round-trip.
  const lastSerialized = useRef(input.value);
  const [mounted, setMounted] = useState(false);

  // Per-mount runtime shared by all extensions (plugins + overlays); stable for editor lifetime so extensions never close over stale state.
  const listenersRef = useRef(new Set<() => void>());
  const keyHandlersRef = useRef(new Set<(event: KeyboardEvent) => boolean>());
  const [api] = useState<ChatComposerEditorApi>(() => ({
    getView: () => viewRef.current,
    subscribe: (listener) => {
      listenersRef.current.add(listener);
      return () => {
        listenersRef.current.delete(listener);
      };
    },
    registerKeyHandler: (handler) => {
      keyHandlersRef.current.add(handler);
      return () => {
        keyHandlersRef.current.delete(handler);
      };
    },
  }));
  // Extensions are mount-time config; capture first set so schema/plugins never rebuild mid-life (would tear down live editor).
  const [initialExtensions] = useState(extensions);

  // Mount once; value/extensions/api read through refs so this never needs to re-run.
  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;
    const exts = initialExtensions;
    const schema = createEditorSchema(exts);

    const extensionKeymap: Record<string, (typeof baseKeymap)[string]> = {};
    for (const extension of exts) Object.assign(extensionKeymap, extension.keymap?.(schema) ?? {});
    const extensionPlugins = exts.flatMap((extension) => extension.plugins?.(schema, api) ?? []);
    const submitMessage = (editorState: EditorState) => {
      const extra: Partial<ChatComposerSubmitPayload> = {};
      for (const extension of exts) Object.assign(extra, extension.submitPayload?.(editorState.doc) ?? {});
      inputRef.current.submit(extra);
      return true;
    };

    const state = EditorState.create({
      schema,
      doc: docFromText(schema, inputRef.current.value),
      plugins: [
        // First so handleKeyDown wins: lets extension overlays (e.g. open mention menu) consume arrow/Enter/Esc before keymaps below.
        new Plugin({
          props: {
            handleKeyDown: (_view, event) => {
              for (const handler of keyHandlersRef.current) if (handler(event)) return true;
              return false;
            },
          },
        }),
        ...extensionPlugins,
        history(),
        // Extension keymaps (e.g. mention Backspace/Delete) before baseKeymap so they win.
        keymap(extensionKeymap),
        keymap({
          "Mod-z": undo,
          "Mod-y": redo,
          "Shift-Mod-z": redo,
          "Shift-Enter": splitBlock,
          [SUBMIT_KEY]: submitMessage,
        }),
        keymap(baseKeymap),
      ],
    });
    const view = new EditorView(mount, {
      state,
      attributes: { "aria-label": "Message", "aria-multiline": "true", role: "textbox" },
      dispatchTransaction(transaction) {
        const next = view.state.apply(transaction);
        view.updateState(next);
        if (transaction.docChanged) {
          const text = serializeDoc(next.doc);
          lastSerialized.current = text;
          inputRef.current.setValue(text);
        }
        // Notify overlays on every transaction (selection moves included) so they can mirror caret state.
        for (const listener of listenersRef.current) listener();
      },
    });
    viewRef.current = view;
    setMounted(true);
    return () => {
      view.destroy();
      viewRef.current = null;
    };
  }, [api, initialExtensions]);

  // Re-hydrate the doc only when the value changes from OUTSIDE the editor (clear/prefill).
  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;
    if (input.value === lastSerialized.current) return;
    // Submit/clear (text→empty): ghost outgoing message so it blurs instead of snapping blank; prefill (edit→non-empty) untouched.
    if (input.value === "" && lastSerialized.current !== "" && view.dom instanceof HTMLElement) {
      spawnExitGhost(view.dom, MESSAGE_GHOST_INHERIT);
    }
    lastSerialized.current = input.value;
    const { schema } = view.state;
    view.updateState(EditorState.create({ schema, doc: docFromText(schema, input.value), plugins: view.state.plugins }));
  }, [input.value]);

  return (
    <div data-control-ui="chat-composer-editor" data-slot="root" className={cn("relative", className)}>
      {input.value === "" && placeholder ? (
        <div
          aria-hidden="true"
          className="pointer-events-none absolute left-[var(--padding-x)] top-[var(--padding-y)] text-sm leading-6 text-muted-foreground"
        >
          {placeholder}
        </div>
      ) : null}
      <div
        ref={mountRef}
        className={cn(
          "[&_.ProseMirror]:max-h-[40dvh] [&_.ProseMirror]:min-h-16 [&_.ProseMirror]:w-full [&_.ProseMirror]:overflow-y-auto [&_.ProseMirror]:whitespace-pre-wrap [&_.ProseMirror]:break-words [&_.ProseMirror]:px-[var(--padding-x)] [&_.ProseMirror]:py-[var(--padding-y)] [&_.ProseMirror]:text-sm [&_.ProseMirror]:leading-6 [&_.ProseMirror]:outline-none",
          mounted ? "" : "hidden",
        )}
      />
      {/* SSR / pre-hydration fallback so the field is visible before the editor mounts (like ChatGPT). */}
      {mounted ? null : (
        <textarea
          aria-label="Message"
          defaultValue={input.value}
          readOnly
          rows={2}
          placeholder={placeholder}
          className="min-h-16 w-full resize-none bg-transparent px-[var(--padding-x)] py-[var(--padding-y)] text-sm leading-6 outline-none placeholder:text-muted-foreground"
        />
      )}
      {/* Extension overlays (caret-anchored popups) render once the view exists. */}
      {mounted
        ? initialExtensions.map((extension) => (extension.Overlay ? <extension.Overlay key={extension.name} editor={api} /> : null))
        : null}
    </div>
  );
}

"use client";

import type { DOMOutputSpec, NodeSpec, Node as ProseMirrorNode } from "prosemirror-model";
import type { Command } from "prosemirror-state";
import type { EditorView } from "prosemirror-view";
import { useEffect } from "react";
import type { MentionItem, TriggerConfig, TriggerMenuItemData } from "@/components/control-ui/contracts";
import { useTriggerMenu } from "@/components/control-ui/hooks/use-trigger-menu";
import { cn } from "@/components/control-ui/lib/cn";
import { detectTrigger } from "@/components/control-ui/lib/trigger-detect";
import { skinSlot } from "@/components/control-ui/skin";
import { TriggerMenu, TriggerMenuEmpty, TriggerMenuIcon, TriggerMenuItem, TriggerMenuList } from "@/components/control-ui/ui/trigger-menu";
import { spawnExitGhost } from "../ghost";
import type { ChatComposerEditorApi, ChatComposerEditorExtension } from "../types";

// Mention extension: "@" pill as one composable unit via mentionExtension({ triggers }) — inline atom node, Backspace/Delete commands, doc→mentions submit extras, caret-anchored popup via trigger-menu engine.
// Base editor stays mention-free.

// PM types attrs as `any`; read each through a typeof guard so we never assert a cast (repo convention).
function attrString(value: unknown, fallback: string): string {
  return typeof value === "string" ? value : fallback;
}

// Pill node: atom + contenteditable=false = non-editable unit (arrows skip it); leafText serializes to "@label"; styled via chat-composer-mention slot (skin-swappable).
const mentionNode: NodeSpec = {
  group: "inline",
  inline: true,
  atom: true,
  selectable: true,
  draggable: false,
  attrs: {
    id: { default: "" },
    label: { default: "" },
    kind: { default: "mention" },
    icon: { default: null },
  },
  parseDOM: [
    {
      tag: "span[data-mention]",
      getAttrs: (dom) => {
        if (typeof dom === "string") return false;
        return {
          id: dom.getAttribute("data-id") ?? "",
          label: dom.textContent ?? "",
          kind: dom.getAttribute("data-mention") ?? "mention",
          icon: dom.getAttribute("data-icon"),
        };
      },
    },
  ],
  toDOM: (node): DOMOutputSpec => {
    const label = attrString(node.attrs.label, "");
    const id = attrString(node.attrs.id, "");
    const kind = attrString(node.attrs.kind, "mention");
    const icon = typeof node.attrs.icon === "string" ? node.attrs.icon : null;
    const attrs = {
      class: cn(
        "inline-flex items-center gap-1 rounded-[var(--radius-popup-item)] bg-primary/10 px-1 align-baseline font-medium text-primary-text",
        skinSlot("chat-composer", "mention", {}),
      ),
      "data-control-ui": "chat-composer",
      "data-slot": "mention",
      "data-mention": kind,
      "data-id": id,
      "data-icon": icon ?? "",
      contenteditable: "false",
    };
    const labelSpan: DOMOutputSpec = ["span", { class: "truncate" }, label];
    return icon === null
      ? ["span", attrs, labelSpan]
      : ["span", attrs, ["img", { src: icon, alt: "", class: "size-4 shrink-0 rounded-[3px]" }], labelSpan];
  },
  leafText: (node) => `@${attrString(node.attrs.label, "")}`,
};

// --- caret trigger reading -----------------------------------------------------------------------

type EditorTriggerState = {
  active: boolean;
  from: number;
  to: number;
  char: string;
  query: string;
  rect: DOMRect | null;
};

const INACTIVE: EditorTriggerState = { active: false, from: 0, to: 0, char: "", query: "", rect: null };

// Reads live trigger at caret off current view (positions never stale); called from overlay on every transaction and its keydown handler.
function readEditorTrigger(view: EditorView, triggerChars: readonly string[]): EditorTriggerState {
  const { selection } = view.state;
  if (!selection.empty) return INACTIVE;
  const { $from } = selection;
  if (!$from.parent.isTextblock) return INACTIVE;
  const start = $from.start();
  // Atoms collapse to one sentinel char so detectTrigger's string offsets map 1:1 onto doc positions.
  const textBefore = view.state.doc.textBetween(start, $from.pos, undefined, () => "￼");
  const match = detectTrigger(textBefore, triggerChars);
  if (match === null) return INACTIVE;
  const coords = view.coordsAtPos($from.pos);
  return {
    active: true,
    from: start + match.start,
    to: $from.pos,
    char: match.char,
    query: match.query,
    rect: new DOMRect(coords.left, coords.top, 1, coords.bottom - coords.top),
  };
}

// --- mutations -----------------------------------------------------------------------------------

type MentionNodeAttrs = { id: string; label: string; kind?: string; icon?: string | null };

// Replace the `<char><query>` range with an atomic mention node followed by a space, then refocus.
function insertMention(view: EditorView, from: number, to: number, attrs: MentionNodeAttrs) {
  const node = view.state.schema.nodes.mention.create({
    id: attrs.id,
    label: attrs.label,
    kind: attrs.kind ?? "mention",
    icon: attrs.icon ?? null,
  });
  const transaction = view.state.tr.replaceWith(from, to, node);
  transaction.insertText(" ");
  view.dispatch(transaction);
  view.focus();
}

// Remove the `<char><query>` token (slash-commands that run an action rather than inserting), refocus.
function deleteTriggerToken(view: EditorView, from: number, to: number) {
  view.dispatch(view.state.tr.delete(from, to));
  view.focus();
}

// Ghosts pill before its transaction lands; pillPos = mention node start, so nodeDOM returns its DOM to clone. Skipped on dry runs / no view (delete lands bare).
function ghostPill(view: EditorView | undefined, pillPos: number): void {
  const dom = view?.nodeDOM(pillPos);
  if (dom instanceof HTMLElement) spawnExitGhost(dom);
}

// Lone atom at block END gets trailing <br> (phantom blank line); plain Backspace looks like it adds a newline instead of removing the pill.
// These commands delete pill + auto-inserted space together in one keystroke, avoiding a lone trailing atom.
// Dispatched run spawns a blur-out ghost first so the pill doesn't just snap out.
export const deleteMentionBackward: Command = (state, dispatch, view) => {
  const { selection } = state;
  if (!selection.empty) return false;
  const { $from } = selection;
  const before = $from.nodeBefore;
  if (!before) return false;
  // Caret directly after a pill → remove the pill.
  if (before.type.name === "mention") {
    const pillPos = $from.pos - before.nodeSize;
    if (dispatch) {
      ghostPill(view, pillPos);
      dispatch(state.tr.delete(pillPos, $from.pos).scrollIntoView());
    }
    return true;
  }
  // Caret past auto-inserted trailing space at block END → drop space+pill together (else pill becomes last node → phantom line); mid-block, dropping just the space is harmless.
  if (before.isText && before.text === " " && $from.pos === $from.end()) {
    const beforeSpace = state.doc.resolve($from.pos - before.nodeSize).nodeBefore;
    if (beforeSpace && beforeSpace.type.name === "mention") {
      const pillPos = $from.pos - before.nodeSize - beforeSpace.nodeSize;
      if (dispatch) {
        ghostPill(view, pillPos);
        dispatch(state.tr.delete(pillPos, $from.pos).scrollIntoView());
      }
      return true;
    }
  }
  return false;
};

// Forward-delete (Del key) symmetry: caret directly before a pill → remove the pill.
export const deleteMentionForward: Command = (state, dispatch, view) => {
  const { selection } = state;
  if (!selection.empty) return false;
  const { $from } = selection;
  const after = $from.nodeAfter;
  if (after?.type.name !== "mention") return false;
  if (dispatch) {
    ghostPill(view, $from.pos);
    dispatch(state.tr.delete($from.pos, $from.pos + after.nodeSize).scrollIntoView());
  }
  return true;
};

// Walks doc for structured mentions (ids+labels) the agent consumes, attached to submit payload alongside plain-text value.
function collectMentions(doc: ProseMirrorNode): MentionItem[] {
  const mentions: MentionItem[] = [];
  doc.descendants((node) => {
    if (node.type.name === "mention") {
      mentions.push({
        id: attrString(node.attrs.id, ""),
        label: attrString(node.attrs.label, ""),
        kind: attrString(node.attrs.kind, "mention"),
      });
    }
  });
  return mentions;
}

// --- overlay -------------------------------------------------------------------------------------

type MentionOverlayProps<Item extends TriggerMenuItemData> = {
  editor: ChatComposerEditorApi;
  triggers: readonly TriggerConfig<Item>[];
  side: "top" | "bottom";
  align: "start" | "center" | "end";
};

// React half: owns trigger-menu controller+popup, talks to doc only via editor api (republish caret trigger, route keys while open, insert pill on commit); no PM plugin needed, keeps base editor mention-unaware.
function MentionOverlay<Item extends TriggerMenuItemData>({ editor, triggers, side, align }: MentionOverlayProps<Item>) {
  const chars = triggers.map((trigger) => trigger.char);

  const controller = useTriggerMenu<Item>({
    triggers,
    onCommit: (item, trigger) => {
      const view = editor.getView();
      if (!view) return;
      const state = readEditorTrigger(view, chars);
      if (!state.active) return;
      if ((trigger.insert ?? "replace") === "none") {
        deleteTriggerToken(view, state.from, state.to);
      } else {
        insertMention(view, state.from, state.to, { id: item.id, label: item.label, kind: item.kind, icon: item.image ?? null });
      }
      trigger.onSelect?.(item, { char: state.char, query: state.query });
    },
  });

  // Republish the caret trigger (and its rect) to the engine on every editor transaction.
  useEffect(() => {
    return editor.subscribe(() => {
      const view = editor.getView();
      if (!view) return;
      const state = readEditorTrigger(view, chars);
      controller.report(state.active ? { char: state.char, query: state.query, start: state.from, end: state.to } : null, state.rect);
    });
  }, [editor, controller, chars]);

  // While the menu is open, let it eat arrows/Enter/Esc before the editor's keymaps see them.
  useEffect(() => {
    return editor.registerKeyHandler((event) => {
      const view = editor.getView();
      if (!view) return false;
      if (!readEditorTrigger(view, chars).active) return false;
      return controller.handleKeyDown(event.key);
    });
  }, [editor, controller, chars]);

  if (triggers.length === 0) return null;
  return (
    <TriggerMenu open={controller.open} onOpenChange={controller.setOpen} anchorRect={controller.anchorRect} side={side} align={align}>
      <TriggerMenuList>
        {controller.items.length === 0 ? (
          <TriggerMenuEmpty>No results</TriggerMenuEmpty>
        ) : (
          controller.items.map((item, index) => (
            <TriggerMenuItem
              key={item.id}
              active={index === controller.activeIndex}
              disabled={item.disabled}
              onPointerMove={() => controller.setActiveIndex(index)}
              onClick={() => controller.select(item)}
            >
              {item.icon ? <TriggerMenuIcon>{item.icon}</TriggerMenuIcon> : null}
              <span className="flex-1 truncate">{item.label}</span>
              {item.description ? <span className="truncate text-micro text-muted-foreground">{item.description}</span> : null}
            </TriggerMenuItem>
          ))
        )}
      </TriggerMenuList>
    </TriggerMenu>
  );
}

// --- factory -------------------------------------------------------------------------------------

export type MentionExtensionConfig<Item extends TriggerMenuItemData = TriggerMenuItemData> = {
  triggers: readonly TriggerConfig<Item>[];
  side?: "top" | "bottom";
  align?: "start" | "center" | "end";
};

export function mentionExtension<Item extends TriggerMenuItemData = TriggerMenuItemData>({
  triggers,
  side = "top",
  align = "start",
}: MentionExtensionConfig<Item>): ChatComposerEditorExtension {
  return {
    name: "mention",
    nodes: { mention: mentionNode },
    keymap: () => ({ Backspace: deleteMentionBackward, Delete: deleteMentionForward }),
    submitPayload: (doc) => ({ mentions: collectMentions(doc) }),
    Overlay: ({ editor }) => <MentionOverlay editor={editor} triggers={triggers} side={side} align={align} />,
  };
}

"use client";

// Exit animation for PM nodes removed synchronously from DOM: node's gone before any transition runs, so @starting-style (entry-only) can't cover the exit.
// Fix: clone element into a fixed-position ghost over its last rect, let editor update immediately, animate ghost out via data-chat-composer-exit/data-exiting (chat-composer-editor.css blur keyframe); self-removes on animationend + timeout backstop.
// Duration from --duration-* tokens (motion kill-switch → instant, no lingering clone); skipped under prefers-reduced-motion.

// Styles the whole-message ghost must carry: .ProseMirror is styled via scoped [&_.ProseMirror] utilities on its mount wrapper, not inherited by a body-appended clone, so copy the ones affecting text rendering. Pill ghost needs none (Tailwind classes + data-slot are global).
const MESSAGE_INHERIT = [
  "font-family",
  "font-size",
  "font-weight",
  "font-style",
  "line-height",
  "letter-spacing",
  "color",
  "padding",
  "white-space",
  "overflow-wrap",
  "word-break",
  "text-align",
] as const;

function prefersReducedMotion(): boolean {
  return typeof window !== "undefined" && typeof window.matchMedia === "function"
    ? window.matchMedia("(prefers-reduced-motion: reduce)").matches
    : false;
}

export function spawnExitGhost(source: HTMLElement, inherit: readonly string[] = []): void {
  if (typeof document === "undefined") return;
  if (prefersReducedMotion()) return;

  const rect = source.getBoundingClientRect();
  if (rect.width === 0 && rect.height === 0) return;

  const ghost = document.createElement(source.tagName.toLowerCase());
  // Copy the source's attributes (class, data-slot, …) so utility + skin styling render identically.
  for (const name of source.getAttributeNames()) {
    const value = source.getAttribute(name);
    if (value !== null) ghost.setAttribute(name, value);
  }
  ghost.innerHTML = source.innerHTML;
  ghost.setAttribute("data-chat-composer-exit", "");
  ghost.setAttribute("data-exiting", "");
  ghost.setAttribute("aria-hidden", "true");
  ghost.removeAttribute("contenteditable");

  if (inherit.length > 0 && typeof getComputedStyle === "function") {
    const computed = getComputedStyle(source);
    for (const property of inherit) ghost.style.setProperty(property, computed.getPropertyValue(property));
  }

  ghost.style.position = "fixed";
  ghost.style.left = `${rect.left}px`;
  ghost.style.top = `${rect.top}px`;
  ghost.style.width = `${rect.width}px`;
  ghost.style.height = `${rect.height}px`;
  ghost.style.margin = "0";
  ghost.style.overflow = "hidden";
  ghost.style.pointerEvents = "none";
  ghost.style.zIndex = "50";

  document.body.appendChild(ghost);

  const remove = () => ghost.remove();
  ghost.addEventListener("animationend", remove, { once: true });
  window.setTimeout(remove, 600);
}

