import type { DOMOutputSpec, NodeSpec } from "prosemirror-model";
import { Schema } from "prosemirror-model";

import type { ChatComposerEditorExtension } from "./types";

// Base composer schema: plain-text paragraphs only; rich nodes (mention pill) come from extensions via createEditorSchema — keep this mention-free for composability.
const baseNodes: Record<string, NodeSpec> = {
  doc: { content: "block+" },
  paragraph: {
    group: "block",
    content: "inline*",
    parseDOM: [{ tag: "p" }],
    toDOM: (): DOMOutputSpec => ["p", 0],
  },
  text: { group: "inline" },
};

// Merges base nodes with every extension's node specs; later extensions win key collisions (each owns a distinct node name in practice).
export function createEditorSchema(extensions: readonly ChatComposerEditorExtension[]): Schema {
  let nodes: Record<string, NodeSpec> = { ...baseNodes };
  for (const extension of extensions) {
    if (extension.nodes) nodes = { ...nodes, ...extension.nodes };
  }
  return new Schema({ nodes, marks: {} });
}

import type { Node as ProseMirrorNode, Schema } from "prosemirror-model";

// Doc is source of truth; these bridge it to chat-composer hook's plain-string value (canSubmit/consumers) and back for external resets (clear, edit-prefill).
// serializeDoc is generic — no mention knowledge; each leaf serializes via its own schema leafText (mention sets "@label"), so extensions stay self-describing.

// Doc → plain text. Blocks join with "\n"; each leaf contributes its schema `leafText` (empty if none).
export function serializeDoc(doc: ProseMirrorNode): string {
  return doc.textBetween(0, doc.content.size, "\n", (leaf) => {
    const leafText = leaf.type.spec.leafText;
    return typeof leafText === "function" ? leafText(leaf) : "";
  });
}

// Plain string → doc, one paragraph per line. Used only for external resets (editor never rebuilds its doc from its own output — would fight caret).
export function docFromText(schema: Schema, text: string): ProseMirrorNode {
  const paragraph = schema.nodes.paragraph;
  const blocks = text.split("\n").map((line) => paragraph.create(null, line === "" ? null : schema.text(line)));
  return schema.nodes.doc.create(null, blocks.length === 0 ? paragraph.create() : blocks);
}

import type { NodeSpec, Node as ProseMirrorNode, Schema } from "prosemirror-model";
import type { Command, Plugin } from "prosemirror-state";
import type { EditorView } from "prosemirror-view";
import type { ReactNode } from "react";

import type { ChatComposerSubmitPayload } from "@/components/control-ui/contracts";

// Runtime handed to every extension: live-view getter, per-transaction subscription (overlays mirror caret/doc state), keydown pre-handler registry (popups swallow arrows/Enter/Esc); stable for editor lifetime.
export type ChatComposerEditorApi = {
  getView: () => EditorView | null;
  subscribe: (listener: () => void) => () => void;
  registerKeyHandler: (handler: (event: KeyboardEvent) => boolean) => () => void;
};

export type ChatComposerEditorOverlayProps = { editor: ChatComposerEditorApi };

// Composable unit of editor behavior; all fields optional — nodes, plugins, keymap, submitPayload extras, Overlay (caret-anchored popup). Mentions are just one such extension.
export type ChatComposerEditorExtension = {
  // Stable unique id (used as overlay's React key); convention: feature name, e.g. "mention".
  name: string;
  nodes?: Record<string, NodeSpec>;
  plugins?: (schema: Schema, editor: ChatComposerEditorApi) => Plugin[];
  keymap?: (schema: Schema) => Record<string, Command>;
  submitPayload?: (doc: ProseMirrorNode) => Partial<ChatComposerSubmitPayload>;
  Overlay?: (props: ChatComposerEditorOverlayProps) => ReactNode;
};

// Props for base rich editor (ProseMirror), composes inside <ChatComposer>; plain <ChatComposerTextarea> still works without it. extensions opts into rich behavior, omit for plain composer.
export type ChatComposerEditorProps = {
  className?: string;
  placeholder?: string;
  extensions?: readonly ChatComposerEditorExtension[];
};

"use client";

import type { ChangeEvent, ComponentProps } from "react";
import { createContext, useContext } from "react";

import type { ChatComposerProps } from "@/components/control-ui/contracts";
import { useChatComposer } from "@/components/control-ui/hooks/use-chat-composer";
import { cn } from "@/components/control-ui/lib/cn";
import { hasSkinAdornment, skinAdornment, skinSlot } from "@/components/control-ui/skin";
import { Button } from "@/components/control-ui/ui/button";

type ChatComposerContextValue = ReturnType<typeof useChatComposer>;

const ChatComposerContext = createContext<ChatComposerContextValue | null>(null);

// Exported so opt-in editor extras (chat-composer-editor.tsx) share this context w/o pulling ProseMirror deps into base file.
export function useChatComposerContext() {
  const context = useContext(ChatComposerContext);
  if (!context) throw new Error("ChatComposer compound components must be rendered inside <ChatComposer>.");
  return context;
}

export function ChatComposer({
  value,
  defaultValue,
  onValueChange,
  onSubmit,
  state = "idle",
  density = "comfortable",
  disabled = false,
  className,
  children,
  ...props
}: ChatComposerProps) {
  const input = useChatComposer({
    value,
    defaultValue,
    onValueChange,
    onSubmit,
    state,
    density,
    disabled,
    trackSends: hasSkinAdornment("chat-composer", "send-layer"),
  });
  const sendLayer = skinAdornment("chat-composer", "send-layer", { sendCount: input.sendCount });

  return (
    <ChatComposerContext.Provider value={input}>
      <form
        data-control-ui="chat-composer"
        data-slot="root"
        data-state={state}
        data-density={density}
        onSubmit={input.handleSubmit}
        className={cn(
          // sticky already makes the form the containing block + stacking context the send-layer anchor relies on
          "sticky bottom-0 w-full bg-background/80 px-2 pb-2 pt-1 backdrop-blur supports-[backdrop-filter]:bg-background/70",
          skinSlot("chat-composer", "root", {}),
          className,
        )}
        {...props}
      >
        {/* send-layer anchor: the component owns this position contract (backdrop behind the shell, hit-test/a11y/paint
            contained); the skin only supplies visuals. Zero DOM when no skin fills the anchor. */}
        {sendLayer !== undefined && sendLayer !== null ? (
          <div aria-hidden="true" className="pointer-events-none absolute inset-0 -z-10 overflow-clip contain-paint">
            {sendLayer}
          </div>
        ) : null}
        {children}
      </form>
    </ChatComposerContext.Provider>
  );
}

